  1→/**
  2→ * Pipeline page interaction logic.
  3→ * Supports dual mode: search-only (no template) and pipeline (with template).
  4→ */
  5→
  6→let pipelineTaskId = null;
  7→let pipelineWS = null;
  8→let pipelineCandidates = [];
  9→
 10→// --- Log helper ---
 11→
 12→function clearLog() {
 13→    const log = document.getElementById('pipeline-log');
 14→    if (log) log.innerHTML = '';
 15→}
 16→
 17→function appendLog(text, level = 'info') {
 18→    const log = document.getElementById('pipeline-log');
 19→    if (!log) return;
 20→    const time = new Date().toLocaleTimeString();
 21→    const line = document.createElement('div');
 22→    line.className = 'log-line';
 23→    line.innerHTML = `<span class="log-time">${time}</span><span class="log-${level}">${escapeHtml(text)}</span>`;
 24→    log.appendChild(line);
 25→    log.scrollTop = log.scrollHeight;
 26→}
 27→
 28→// --- Form submission ---
 29→
 30→document.getElementById('pipeline-form').addEventListener('submit', async (e) => {
 31→    e.preventDefault();
 32→    const form = e.target;
 33→
 34→    const keywords = form.keywords.value.split('\n').map(s => s.trim()).filter(Boolean);
 35→    const company = form.company.value.split('\n').map(s => s.trim()).filter(Boolean);
 36→    const location = form.location ? form.location.value.trim() || null : null;
 37→    const template = form.template.value;
 38→    const pages = parseInt(form.pages.value) || 1;
 39→
 40→    if (!keywords.length) return alert('Please enter at least one keyword');
 41→
 42→    // Hide all result sections, reset log
 43→    document.getElementById('pipeline-progress').hidden = false;
 44→    document.getElementById('pipeline-confirm').hidden = true;
 45→    document.getElementById('pipeline-results').hidden = true;
 46→    document.getElementById('search-results').hidden = true;
 47→    document.getElementById('pipeline-progress-bar').value = 0;
 48→    form.querySelector('button[type="submit"]').disabled = true;
 49→    clearLog();
 50→
 51→    const isSearchOnly = !template;
 52→
 53→    if (isSearchOnly) {
 54→        // --- Search-only mode ---
 55→        appendLog(`Starting search: ${keywords.join(', ')} | pages=${pages}`);
 56→        try {
 57→            const res = await fetch('/api/search', {
 58→                method: 'POST',
 59→                headers: {'Content-Type': 'application/json'},
 60→                body: JSON.stringify({keywords, company, location, pages}),
 61→            });
 62→            if (!res.ok) throw new Error(`Search request failed: HTTP ${res.status}`);
 63→            const data = await res.json();
 64→            pipelineTaskId = data.task_id;
 65→            document.getElementById('pipeline-task-id').textContent = data.task_id;
 66→            document.getElementById('pipeline-status-text').textContent = 'Searching...';
 67→            appendLog(`Task queued: ${data.task_id}`);
 68→
 69→            connectTaskWS(data.task_id, {
 70→                onEvent(msg) {
 71→                    document.getElementById('pipeline-status-text').textContent =
 72→                        `${msg.event}: ${msg.keyword || ''} ${msg.found ? '(' + msg.found + ' found)' : ''}`;
 73→                    if (msg.event === 'search_keyword_done') {
 74→                        appendLog(`"${msg.keyword}" — found ${msg.found} candidates (total: ${msg.total_so_far})`, 'ok');
 75→                    } else if (msg.keyword) {
 76→                        appendLog(`Searching: ${msg.keyword}`);
 77→                    }
 78→                },
 79→                onComplete(msg) {
 80→                    const candidates = msg.result || [];
 81→                    appendLog(`Search complete — ${candidates.length} candidates found`, 'ok');
 82→                    showSearchResults(candidates);
 83→                    document.getElementById('pipeline-progress').hidden = true;
 84→                    form.querySelector('button[type="submit"]').disabled = false;
 85→                },
 86→                onError(msg) {
 87→                    const err = msg.error || 'Unknown error';
 88→                    appendLog(`Search failed: ${err}`, 'err');
 89→                    document.getElementById('pipeline-status-text').textContent = 'Failed';
 90→                    form.querySelector('button[type="submit"]').disabled = false;
 91→                },
 92→            });
 93→        } catch (e) {
 94→            appendLog(`Request failed: ${e.message}`, 'err');
 95→            document.getElementById('pipeline-progress').hidden = true;
 96→            form.querySelector('button[type="submit"]').disabled = false;
 97→        }
 98→    } else {
 99→        // --- Pipeline mode ---
100→        const auto_send = form.auto_send.checked;
101→
102→        // Collect template variables
103→        const variables = {};
104→        form.querySelectorAll('[name^="var_"]').forEach(input => {
105→            const key = input.name.replace('var_', '');
106→            if (input.value.trim()) variables[key] = input.value.trim();
107→        });
108→
109→        appendLog(`Starting pipeline: ${keywords.join(', ')} | template=${template} | auto_send=${auto_send}`);
110→
111→        try {
112→            const res = await fetch('/api/pipeline', {
113→                method: 'POST',
114→                headers: {'Content-Type': 'application/json'},
115→                body: JSON.stringify({keywords, company, location, template, pages, variables, auto_send}),
116→            });
117→            if (!res.ok) throw new Error(`Pipeline request failed: HTTP ${res.status}`);
118→            const data = await res.json();
119→            pipelineTaskId = data.task_id;
120→            document.getElementById('pipeline-task-id').textContent = data.task_id;
121→            appendLog(`Task queued: ${data.task_id}`);
122→
123→            pipelineWS = connectTaskWS(data.task_id, {
124→                onEvent(msg) {
125→                    handlePipelineEvent(msg);
126→                },
127→                onComplete(msg) {
128→                    appendLog('Pipeline completed', 'ok');
129→                    showPipelineResults(msg.result);
130→                    document.getElementById('pipeline-progress').hidden = true;
131→                    form.querySelector('button[type="submit"]').disabled = false;
132→                },
133→                onError(msg) {
134→                    const err = msg.error || 'Unknown error';
135→                    appendLog(`Pipeline failed: ${err}`, 'err');
136→                    document.getElementById('pipeline-status-text').textContent = 'Failed';
137→                    document.getElementById('pipeline-detail').textContent = err;
138→                    form.querySelector('button[type="submit"]').disabled = false;
139→                },
140→            });
141→
142→            pollTask(data.task_id, (task) => {
143→                if (task.status === 'completed') {
144→                    showPipelineResults(task.result);
145→                    document.getElementById('pipeline-progress').hidden = true;
146→                    form.querySelector('button[type="submit"]').disabled = false;
147→                    if (pipelineWS) pipelineWS.close();
148→                }
149→            }, 3000);
150→
151→        } catch (e) {
152→            appendLog(`Request failed: ${e.message}`, 'err');
153→            form.querySelector('button[type="submit"]').disabled = false;
154→            document.getElementById('pipeline-progress').hidden = true;
155→        }
156→    }
157→});
158→
159→function handlePipelineEvent(msg) {
160→    const statusEl = document.getElementById('pipeline-status-text');
161→    const detailEl = document.getElementById('pipeline-detail');
162→    const progressBar = document.getElementById('pipeline-progress-bar');
163→
164→    switch (msg.event) {
165→        case 'search_progress':
166→            statusEl.textContent = `Searching: ${msg.keyword} (${msg.keyword_index}/${msg.total_keywords})`;
167→            appendLog(`Searching keyword ${msg.keyword_index}/${msg.total_keywords}: "${msg.keyword}"`);
168→            break;
169→
170→        case 'search_keyword_done':
171→            detailEl.textContent = `Found ${msg.found} candidates for "${msg.keyword}" (${msg.total_so_far} total)`;
172→            appendLog(`"${msg.keyword}" — found ${msg.found} (total: ${msg.total_so_far})`, 'ok');
173→            break;
174→
175→        case 'search_complete':
176→            statusEl.textContent = 'Search complete';
177→            detailEl.textContent = `${msg.candidates.length} candidates found`;
178→            appendLog(`Search phase done — ${msg.candidates.length} candidates`, 'ok');
179→            break;
180→
181→        case 'awaiting_confirmation':
182→            statusEl.textContent = 'Awaiting your confirmation';
183→            appendLog(`Waiting for confirmation — ${msg.candidates.length} candidates to review`, 'warn');
184→            document.getElementById('pipeline-progress').hidden = true;
185→            showConfirmation(msg.candidates);
186→            break;
187→
188→        case 'sending_started':
189→            statusEl.textContent = 'Sending messages...';
190→            progressBar.max = msg.total;
191→            progressBar.value = 0;
192→            document.getElementById('pipeline-progress').hidden = false;
193→            document.getElementById('pipeline-confirm').hidden = true;
194→            appendLog(`Sending messages to ${msg.total} candidates...`);
195→            break;
196→
197→        case 'send_progress':
198→            statusEl.textContent = `Sending: ${msg.current} (${msg.sent}/${msg.total})`;
199→            progressBar.value = msg.sent + msg.failed;
200→            progressBar.max = msg.total;
201→            detailEl.textContent = `Sent: ${msg.sent}, Failed: ${msg.failed}`;
202→            if (msg.status === 'sent') {
203→                appendLog(`Sent to ${msg.current}`, 'ok');
204→            } else if (msg.status === 'failed') {
205→                appendLog(`Failed: ${msg.current} — ${msg.error || 'unknown'}`, 'err');
206→            } else if (msg.status === 'skipped') {
207→                appendLog(`Skipped: ${msg.current}`, 'warn');
208→            } else {
209→                appendLog(`${msg.current} (${msg.sent}/${msg.total})`);
210→            }
211→            break;
212→
213→        case 'completed':
214→            appendLog('Pipeline completed', 'ok');
215→            showPipelineResults(msg.result);
216→            break;
217→
218→        default:
219→            appendLog(`${msg.event}: ${JSON.stringify(msg)}`);
220→    }
221→}
