223→function showConfirmation(candidates) {
224→    pipelineCandidates = candidates;
225→    document.getElementById('pipeline-confirm').hidden = false;
226→    document.getElementById('confirm-count').textContent = candidates.length;
227→
228→    const list = document.getElementById('candidate-list');
229→    list.innerHTML = candidates.map(c => `
230→        <label>
231→            <input type="checkbox" value="${escapeHtml(c.maimai_id)}" checked>
232→            <span class="candidate-info">
233→                <span class="candidate-name">${escapeHtml(c.name)}</span>
234→                <span class="candidate-title">${escapeHtml(c.title)}</span>
235→                <span class="candidate-company">${escapeHtml(c.company)}</span>
236→            </span>
237→        </label>
238→    `).join('');
239→}
240→
241→function toggleSelectAll(checked) {
242→    document.querySelectorAll('#candidate-list input[type="checkbox"]').forEach(cb => {
243→        cb.checked = checked;
244→    });
245→}
246→
247→async function confirmCandidates(cancel = false) {
248→    if (!pipelineTaskId) return;
249→
250→    let maimai_ids = [];
251→    if (!cancel) {
252→        document.querySelectorAll('#candidate-list input[type="checkbox"]:checked').forEach(cb => {
253→            maimai_ids.push(cb.value);
254→        });
255→
256→        if (!maimai_ids.length) {
257→            return alert('Please select at least one candidate');
258→        }
259→    }
260→
261→    try {
262→        await fetch(`/api/pipeline/${pipelineTaskId}/confirm`, {
263→            method: 'POST',
264→            headers: {'Content-Type': 'application/json'},
265→            body: JSON.stringify({maimai_ids}),
266→        });
267→
268→        document.getElementById('pipeline-confirm').hidden = true;
269→        if (!cancel) {
270→            document.getElementById('pipeline-progress').hidden = false;
271→            document.getElementById('pipeline-status-text').textContent = 'Sending messages...';
272→            appendLog(`Confirmed ${maimai_ids.length} candidates, sending...`);
273→        } else {
274→            appendLog('Cancelled by user', 'warn');
275→        }
276→    } catch (e) {
277→        appendLog(`Confirm failed: ${e.message}`, 'err');
278→        alert('Confirm failed: ' + e.message);
279→    }
280→}
281→
282→// --- Search-only results ---
283→
284→function showSearchResults(candidates) {
285→    document.getElementById('search-results').hidden = false;
286→    document.getElementById('result-count').textContent = candidates.length;
287→    const tbody = document.getElementById('results-body');
288→    tbody.innerHTML = candidates.map((c, i) => `
289→        <tr>
290→            <td>${i + 1}</td>
291→            <td>${escapeHtml(c.name)}</td>
292→            <td>${escapeHtml(c.title)}</td>
293→            <td>${escapeHtml(c.company)}</td>
294→            <td>${escapeHtml(c.location || '')}</td>
295→        </tr>
296→    `).join('');
297→}
298→
299→async function exportResults() {
300→    try {
301→        const res = await fetch('/api/export', {
302→            method: 'POST',
303→            headers: {'Content-Type': 'application/json'},
304→            body: JSON.stringify({format: 'xlsx'}),
305→        });
306→        if (!res.ok) throw new Error(`Export failed: HTTP ${res.status}`);
307→        const blob = await res.blob();
308→        const url = URL.createObjectURL(blob);
309→        const a = document.createElement('a');
310→        a.href = url;
311→        a.download = 'candidates.xlsx';
312→        a.click();
313→        URL.revokeObjectURL(url);
314→    } catch (e) {
315→        alert('Export failed: ' + e.message);
316→    }
317→}
318→
319→// --- Pipeline results ---
320→
321→function showPipelineResults(result) {
322→    document.getElementById('pipeline-progress').hidden = true;
323→    document.getElementById('pipeline-confirm').hidden = true;
324→    document.getElementById('pipeline-results').hidden = false;
325→
326→    const summary = document.getElementById('results-summary');
327→
328→    if (!result || result.error) {
329→        summary.innerHTML = `<p>Error: ${escapeHtml(result ? result.error : 'Unknown')}</p>`;
330→        return;
331→    }
332→
333→    if (result.dry_run) {
334→        summary.innerHTML = `
335→            <p>Dry run complete. Found <strong>${result.total}</strong> candidates.</p>
336→            <p>No messages were sent.</p>
337→        `;
338→        return;
339→    }
340→
341→    if (result.message) {
342→        summary.innerHTML = `<p>${escapeHtml(result.message)}</p>`;
343→        return;
344→    }
345→
346→    summary.innerHTML = `
347→        <div class="stat-grid">
348→            <div class="stat">
349→                <div class="value">${result.total || 0}</div>
350→                <div class="label">Total</div>
351→            </div>
352→            <div class="stat" style="color: #155724">
353→                <div class="value">${result.sent || 0}</div>
354→                <div class="label">Sent</div>
355→            </div>
356→            <div class="stat" style="color: #721c24">
357→                <div class="value">${result.failed || 0}</div>
358→                <div class="label">Failed</div>
359→            </div>
360→            <div class="stat" style="color: #856404">
361→                <div class="value">${result.skipped || 0}</div>
362→                <div class="label">Skipped</div>
363→            </div>
364→            <div class="stat" style="color: #856404">
365→                <div class="value">${result.rate_limited || 0}</div>
366→                <div class="label">Rate Limited</div>
367→            </div>
368→        </div>
369→    `;
370→}
